from dataclasses import dataclassfrom collections.abc import Iteratorfrom criresviz.database.loader import load_settings_databasefrom .molecule import Moleculefrom .order import Orderfrom .detector import Detectorimport pandas as pd@dataclass(slots=True)class CRIRESSetting:    """    Representation of a CRIRES+ wavelength setting.    A CRIRES+ setting consists of several echelle orders, each split across    three detectors. Instances are typically created using    :meth:`from_name`, which loads the instrument configuration from the    bundled CRIRES+ database.    Parameters    ----------    name : str        CRIRES+ setting name (e.g. ``"L3262"``).    band : str        Spectral band of the setting.    reference_wavelength : float        Central wavelength of the setting in μm.    orders : list[Order]        List of echelle orders belonging to the setting.    """        name: str    band: str    reference_wavelength: float    orders: list[Order]        # properties        @property    def wavelength_range(self):        """        Overall wavelength coverage of the setting.        Returns        -------        tuple[float, float]            Minimum and maximum wavelength covered by all orders.        """        return (            min(order.wavelength_min for order in self.orders),            max(order.wavelength_max for order in self.orders),        )    @property    def order_numbers(self):        """Return the available echelle order numbers."""        return [order.number for order in self.orders]            @property    def n_orders(self):        """Number of echelle orders."""        return len(self.orders)        # constructors        @classmethod    def from_name(cls, name: str):        """        Load a CRIRES+ setting from the internal database.        Parameters        ----------        name : str            CRIRES+ setting name (e.g. ``"M4368"``).        Returns        -------        CRIRESSetting            Fully initialized setting containing all orders and detectors.        Raises        ------        KeyError            If the requested setting does not exist in the database.        """        database = load_settings_database()        try:            info = database[name]        except KeyError:            raise ValueError(                f"Unknown setting: '{name}'. "                f"Check CRIRES+ settings with CRIRESSetting.info()"            )                    orders = []                for order_number, order_info in info["orders"].items():                    detector1 = Detector(                number=1,                wavelength_min=order_info["detector1"]["min"],                wavelength_max=order_info["detector1"]["max"],            )                    detector2 = Detector(                number=2,                wavelength_min=order_info["detector2"]["min"],                wavelength_max=order_info["detector2"]["max"],            )                    detector3 = Detector(                number=3,                wavelength_min=order_info["detector3"]["min"],                wavelength_max=order_info["detector3"]["max"],            )                    orders.append(                Order(                    number=int(order_number),                    detector1=detector1,                    detector2=detector2,                    detector3=detector3,                )            )                    orders = sorted(            orders,            key=lambda order: order.number,            reverse=True,            )        return cls(            name=name,            band=info["band"],            reference_wavelength=info["reference_wavelength"],            orders=orders        )        @classmethod    def info(cls, band: str | None = None) -> pd.DataFrame:        """        Return a summary of the available CRIRES+ wavelength settings.        Parameters        ----------        band : str, optional            Spectral band to display ("Y", "J", "H", "K", "L", or "M").            If a specific specral setting in specified (e.g. M4368), the             "__str__" is called. If omitted, all settings are returned.        Returns        -------        pandas.DataFrame            Table containing one row per wavelength setting.        Examples        --------        >>> CRIRESSetting.info()        >>> CRIRESSetting.info("L")        >>> CRIRESSetting.info("M")                >>> CRIRESSetting.info("M4368")        """        database = load_settings_database()        rows = []        for name, setting in database.items():                        order_numbers = sorted(                int(k)                for k in setting["orders"]            )                        orders = f"{order_numbers[0]}–{order_numbers[-1]}"            rows.append(                {                    "setting": name,                    "band": setting["band"],                    "reference_wavelength [μm]": setting["reference_wavelength"],                    "wavelength_min [μm]": min(                        order["detector1"]["min"]                        for order in setting["orders"].values()                    ),                    "wavelength_max [μm]": max(                        order["detector3"]["max"]                        for order in setting["orders"].values()                    ),                    "orders": orders,                }            )        df = (            pd.DataFrame(rows)            .sort_values("reference_wavelength [μm]")            .reset_index(drop=True)        )        if band is not None:                        if band.upper() in database:                setting = cls.from_name(band.upper())                            print(setting)                            return 0            else:                band = band.upper()                    valid = {"Y", "J", "H", "K", "L", "M"}                    if band not in valid:                    raise ValueError(                        f"Unknown band '{band}'. "                        f"Choose one of {sorted(valid)}."                    )                    df = (                    df[df["band"] == band]                    .reset_index(drop=True)                )        print(df)                return df                @classmethod    def rank(cls, molecule, sky=None, verbose=True):                rows = []                database = load_settings_database()                for name in database:                    setting = cls.from_name(name)                    coverage = setting.coverage(                molecule,                verbose=False,            )                    row = {                "Setting": name,                "Coverage": coverage,            }                    if sky is not None:                        transmission = sky.mean_transmission(wavelength_range=setting.wavelength_range)                        radiance = sky.mean_radiance(wavelength_range=setting.wavelength_range)                max_radiance = sky.radiance.max()                radiance_score = 1 - radiance / max_radiance                score = coverage * transmission * radiance_score                        row["Transmission"] = transmission                row["Radiance Score"] = radiance_score                row["Score"] = score                    else:                        row["Score"] = coverage                    rows.append(row)                results = pd.DataFrame(rows)        results = results.sort_values(            by="Score",            ascending=False,        ).reset_index(drop=True)        pd.options.display.float_format = "{:,.2f}".format                if verbose:            print(results)                    return results                @classmethod    def _database(cls):        """Return the CRIRES+ settings database."""        return load_settings_database()            @classmethod    def _available_settings(cls):        """Return all available setting names."""        return sorted(cls._database().keys())        @classmethod    def find_best_setting(cls, molecule, sky=None):        """        Return the best ranked setting, according        to the score derived in the rank function        """        rank = cls.rank(molecule, sky=sky, verbose=False)        print(rank.iloc[0])        return rank.iloc[0]        # public methods        def __iter__(self) -> Iterator[Order]:        """        Iterate over the echelle orders.                Yields        ------        Order            Orders belonging to the setting.        """        return iter(self.orders)            ##############################################    def get_order(self, number: int) -> Order:        """        Return a specific echelle order.        Parameters        ----------        number : int            Order number.        Returns        -------        Order            Requested order.        Raises        ------        ValueError            If the order is not present in the setting.        """            for order in self.orders:                if order.number == number:                return order            raise ValueError(            f"Order {number} not found."        )     ##############################################        def coverage(self, *molecules, decimals=2, verbose=True):        """        Compute the detector coverage of one or more molecules.            Coverage is defined as the percentage of the total detector wavelength        covered by the active opacity regions of each molecule.            Parameters        ----------        *molecules : Molecule            One or more Molecule objects.        decimals : int or None, optional            Number of decimal places used to round the result.            Returns        -------        float, dict[str, float], or str            - float if a single molecule is provided.            - dict if multiple molecules are provided.            - formatted table if no molecules are provided.        """                lines = [            "Species      Coverage",            "─────────────────────",        ]            if not molecules:            molecules = [                Molecule.from_name(name)                for name in Molecule.available()            ]                    # Merge detector wavelength intervals        intervals = []            for order in self:            for detector in order:                intervals.append(                    (                        detector.wavelength_min,                        detector.wavelength_max,                    )                )            intervals.sort()            merged = []            for start, end in intervals:                if not merged:                merged.append([start, end])                elif start <= merged[-1][1]:                merged[-1][1] = max(                    merged[-1][1],                    end,                )                else:                merged.append([start, end])            total = sum(            end - start            for start, end in merged        )                    # Compute molecular coverage        results = {}            for molecule in molecules:                covered = 0.0                for det_start, det_end in merged:                    for mol_start, mol_end in molecule.active_regions:                        covered += max(                        0.0,                        min(det_end, mol_end)                        - max(det_start, mol_start),                    )                value = 100 * covered / total                if decimals is not None:                value = round(value, decimals)                results[molecule.name] = value            coverage = value                    # Return result        if verbose:            for name, value in sorted(results.items()):                    lines.append(f"{name:<10} {value:>7.2f} %")                            table = "\n".join(lines)            print(table)                 return coverage    # dunder methods        def __str__(self):            return (            "CRIRES+ Setting\n"            "──────────────────────────────\n"            f"Name:                 {self.name}\n"            f"Band:                 {self.band}\n"            f"Reference wavelength: {self.reference_wavelength:.3f} μm\n"                        f"Orders:               {len(self.orders)}\n"            f"Wavelength range:     "            f"{self.wavelength_range[0]:.3f}–"            f"{self.wavelength_range[1]:.3f} μm"        )    